45: DefaultCertValidator::DefaultCertValidator(
46:     const Envoy::Ssl::CertificateValidationContextConfig* config, SslStats& stats,
47:     Server::Configuration::CommonFactoryContext& context)
48:     : config_(config), stats_(stats), context_(context) {
49:   if (config_ != nullptr) {
50:     allow_untrusted_certificate_ = config_->trustChainVerification() ==
51:                                    envoy::extensions::transport_sockets::tls::v3::
52:                                        CertificateValidationContext::ACCEPT_UNTRUSTED;
53:   }
54: };
55: 
56: absl::StatusOr<int> DefaultCertValidator::initializeSslContexts(std::vector<SSL_CTX*> contexts,
57:                                                                 bool provides_certificates) {
58: 
59:   int verify_mode = SSL_VERIFY_NONE;
60:   int verify_mode_validation_context = SSL_VERIFY_PEER | SSL_VERIFY_FAIL_IF_NO_PEER_CERT;
61: 
62:   if (config_ != nullptr) {
63:     envoy::extensions::transport_sockets::tls::v3::CertificateValidationContext::
64:         TrustChainVerification verification = config_->trustChainVerification();
65:     if (verification == envoy::extensions::transport_sockets::tls::v3::
66:                             CertificateValidationContext::ACCEPT_UNTRUSTED) {
67:       verify_mode = SSL_VERIFY_PEER; // Ensure client-certs will be requested even if we have
68:                                      // nothing to verify against
69:       verify_mode_validation_context = SSL_VERIFY_PEER;
70:     }
71:   }
72: 
73:   if (config_ != nullptr && !config_->caCert().empty() && !provides_certificates) {
74:     ca_file_path_ = config_->caCertPath();
75:     bssl::UniquePtr<BIO> bio(
76:         BIO_new_mem_buf(const_cast<char*>(config_->caCert().data()), config_->caCert().size()));
77:     RELEASE_ASSERT(bio != nullptr, "");
78:     // Based on BoringSSL's X509_load_cert_crl_file().
79:     bssl::UniquePtr<STACK_OF(X509_INFO)> list(
80:         PEM_X509_INFO_read_bio(bio.get(), nullptr, nullptr, nullptr));
81:     if (list == nullptr) {
82:       return absl::InvalidArgumentError(
83:           absl::StrCat("Failed to load trusted CA certificates from ", config_->caCertPath()));
84:     }
85: 
86:     for (auto& ctx : contexts) {
87:       X509_STORE* store = SSL_CTX_get_cert_store(ctx);
88:       X509_STORE_set_flags(store, X509_V_FLAG_PARTIAL_CHAIN);
89:       bool has_crl = false;
90:       for (const X509_INFO* item : list.get()) {
91:         if (item->x509) {
92:           X509_STORE_add_cert(store, item->x509);
93:           if (ca_cert_ == nullptr) {
94:             X509_up_ref(item->x509);
95:             ca_cert_.reset(item->x509);
96:           }
97:         }
98:         if (item->crl) {
99:           X509_STORE_add_crl(store, item->crl);
100:           has_crl = true;
101:         }
102:       }
103:       if (ca_cert_ == nullptr) {
104:         return absl::InvalidArgumentError(
105:             absl::StrCat("Failed to load trusted CA certificates from ", config_->caCertPath()));
106:       }
107:       if (has_crl) {
108:         X509_STORE_set_flags(store, config_->onlyVerifyLeafCertificateCrl()
109:                                         ? X509_V_FLAG_CRL_CHECK
110:                                         : X509_V_FLAG_CRL_CHECK | X509_V_FLAG_CRL_CHECK_ALL);
111:       }
112:       verify_mode = SSL_VERIFY_PEER;
113:       verify_trusted_ca_ = true;
114: 
115:       if (config_->allowExpiredCertificate()) {
116:         CertValidatorUtil::setIgnoreCertificateExpiration(store);
117:       }
118:     }
119:   }
120: 
121:   if (config_ != nullptr && !config_->certificateRevocationList().empty()) {
122:     bssl::UniquePtr<BIO> bio(
123:         BIO_new_mem_buf(const_cast<char*>(config_->certificateRevocationList().data()),
124:                         config_->certificateRevocationList().size()));
125:     RELEASE_ASSERT(bio != nullptr, "");
126: 
127:     // Based on BoringSSL's X509_load_cert_crl_file().
128:     bssl::UniquePtr<STACK_OF(X509_INFO)> list(
129:         PEM_X509_INFO_read_bio(bio.get(), nullptr, nullptr, nullptr));
130:     if (list == nullptr) {
131:       return absl::InvalidArgumentError(
132:           absl::StrCat("Failed to load CRL from ", config_->certificateRevocationListPath()));
133:     }
134: 
135:     for (auto& ctx : contexts) {
136:       X509_STORE* store = SSL_CTX_get_cert_store(ctx);
137:       X509_STORE_set_flags(store, X509_V_FLAG_PARTIAL_CHAIN);
138:       for (const X509_INFO* item : list.get()) {
139:         if (item->crl) {
140:           X509_STORE_add_crl(store, item->crl);
141:         }
142:       }
143:       X509_STORE_set_flags(store, config_->onlyVerifyLeafCertificateCrl()
144:                                       ? X509_V_FLAG_CRL_CHECK
145:                                       : X509_V_FLAG_CRL_CHECK | X509_V_FLAG_CRL_CHECK_ALL);
146:     }
147:   }
148: 
149:   const Envoy::Ssl::CertificateValidationContextConfig* cert_validation_config = config_;
150:   if (cert_validation_config != nullptr) {
151:     if (!cert_validation_config->subjectAltNameMatchers().empty()) {
152:       for (const envoy::extensions::transport_sockets::tls::v3::SubjectAltNameMatcher& matcher :
153:            cert_validation_config->subjectAltNameMatchers()) {
154:         auto san_matcher = createStringSanMatcher(matcher, context_);
155:         if (san_matcher == nullptr) {
156:           return absl::InvalidArgumentError(
157:               absl::StrCat("Failed to create string SAN matcher of type ", matcher.san_type()));
158:         }
159:         subject_alt_name_matchers_.push_back(std::move(san_matcher));
160:       }
161:       verify_mode = verify_mode_validation_context;
162:     }
163: 
164:     if (!cert_validation_config->verifyCertificateHashList().empty()) {
165:       for (auto hash : cert_validation_config->verifyCertificateHashList()) {
166:         // Remove colons from the 95 chars long colon-separated "fingerprint"
167:         // in order to get the hex-encoded string.
168:         if (hash.size() == 95) {
169:           hash.erase(std::remove(hash.begin(), hash.end(), ':'), hash.end());
170:         }
171:         const auto& decoded = Hex::decode(hash);
172:         if (decoded.size() != SHA256_DIGEST_LENGTH) {
173:           return absl::InvalidArgumentError(absl::StrCat("Invalid hex-encoded SHA-256 ", hash));
174:         }
175:         verify_certificate_hash_list_.push_back(decoded);
176:       }
177:       verify_mode = verify_mode_validation_context;
178:     }
179: 
180:     if (!cert_validation_config->verifyCertificateSpkiList().empty()) {
181:       for (const auto& hash : cert_validation_config->verifyCertificateSpkiList()) {
182:         const auto decoded = Base64::decode(hash);
183:         if (decoded.size() != SHA256_DIGEST_LENGTH) {
184:           return absl::InvalidArgumentError(absl::StrCat("Invalid base64-encoded SHA-256 ", hash));
185:         }
186:         verify_certificate_spki_list_.emplace_back(decoded.begin(), decoded.end());
187:       }
188:       verify_mode = verify_mode_validation_context;
189:     }
190:   }
191: 
192:   return verify_mode;
193: }
