222: Envoy::Ssl::ClientValidationStatus
223: DefaultCertValidator::verifyCertificate(X509* cert, const std::vector<std::string>& verify_san_list,
224:                                         const std::vector<SanMatcherPtr>& subject_alt_name_matchers,
225:                                         std::string* error_details, uint8_t* out_alert) {
226:   Envoy::Ssl::ClientValidationStatus validated = Envoy::Ssl::ClientValidationStatus::NotValidated;
227:   if (!verify_san_list.empty()) {
228:     if (!verifySubjectAltName(cert, verify_san_list)) {
229:       const char* error = "verify cert failed: verify SAN list";
230:       if (error_details != nullptr) {
231:         *error_details = error;
232:       }
233:       ENVOY_LOG(debug, error);
234:       stats_.fail_verify_san_.inc();
235:       return Envoy::Ssl::ClientValidationStatus::Failed;
236:     }
237:     validated = Envoy::Ssl::ClientValidationStatus::Validated;
238:   }
239: 
240:   if (!subject_alt_name_matchers.empty()) {
241:     if (!matchSubjectAltName(cert, subject_alt_name_matchers)) {
242:       const char* error = "verify cert failed: SAN matcher";
243:       if (error_details != nullptr) {
244:         *error_details = error;
245:       }
246:       ENVOY_LOG(debug, error);
247:       stats_.fail_verify_san_.inc();
248:       return Envoy::Ssl::ClientValidationStatus::Failed;
249:     }
250:     validated = Envoy::Ssl::ClientValidationStatus::Validated;
251:   }
252: 
253:   if (!verify_certificate_hash_list_.empty() || !verify_certificate_spki_list_.empty()) {
254:     const bool valid_certificate_hash =
255:         !verify_certificate_hash_list_.empty() &&
256:         verifyCertificateHashList(cert, verify_certificate_hash_list_);
257:     const bool valid_certificate_spki =
258:         !verify_certificate_spki_list_.empty() &&
259:         verifyCertificateSpkiList(cert, verify_certificate_spki_list_);
260: 
261:     if (!valid_certificate_hash && !valid_certificate_spki) {
262:       if (out_alert != nullptr) {
263:         *out_alert = SSL_AD_BAD_CERTIFICATE_HASH_VALUE;
264:       }
265:       const char* error = "verify cert failed: cert hash and spki";
266:       if (error_details != nullptr) {
267:         *error_details = error;
268:       }
269:       ENVOY_LOG(debug, error);
270:       stats_.fail_verify_cert_hash_.inc();
271:       return Envoy::Ssl::ClientValidationStatus::Failed;
272:     }
273: 
274:     validated = Envoy::Ssl::ClientValidationStatus::Validated;
275:   }
276: 
277:   return validated;
278: }
