343: bool DefaultCertValidator::verifySubjectAltName(X509* cert,
344:                                                 const std::vector<std::string>& subject_alt_names) {
345:   bssl::UniquePtr<GENERAL_NAMES> san_names(
346:       static_cast<GENERAL_NAMES*>(X509_get_ext_d2i(cert, NID_subject_alt_name, nullptr, nullptr)));
347:   if (san_names == nullptr) {
348:     return false;
349:   }
350:   for (const GENERAL_NAME* general_name : san_names.get()) {
351:     const std::string san = Utility::generalNameAsString(general_name);
352:     for (auto& config_san : subject_alt_names) {
353:       if (general_name->type == GEN_DNS ? Utility::dnsNameMatch(config_san, san.c_str())
354:                                         : config_san == san) {
355:         return true;
356:       }
357:     }
358:   }
359:   return false;
360: }
