68: ContextImpl::ContextImpl(Stats::Scope& scope, const Envoy::Ssl::ContextConfig& config,
69:                          Server::Configuration::CommonFactoryContext& factory_context,
70:                          Ssl::ContextAdditionalInitFunc additional_init,
71:                          absl::Status& creation_status)
72:     : scope_(scope), stats_(generateSslStats(scope)), factory_context_(factory_context),
73:       tls_max_version_(config.maxProtocolVersion()),
74:       stat_name_set_(scope.symbolTable().makeSet("TransportSockets::Tls")),
75:       unknown_ssl_cipher_(stat_name_set_->add("unknown_ssl_cipher")),
76:       unknown_ssl_curve_(stat_name_set_->add("unknown_ssl_curve")),
77:       unknown_ssl_algorithm_(stat_name_set_->add("unknown_ssl_algorithm")),
78:       unknown_ssl_version_(stat_name_set_->add("unknown_ssl_version")),
79:       ssl_ciphers_(stat_name_set_->add("ssl.ciphers")),
80:       ssl_versions_(stat_name_set_->add("ssl.versions")),
81:       ssl_curves_(stat_name_set_->add("ssl.curves")),
82:       ssl_sigalgs_(stat_name_set_->add("ssl.sigalgs")), capabilities_(config.capabilities()),
83:       tls_keylog_local_(config.tlsKeyLogLocal()), tls_keylog_remote_(config.tlsKeyLogRemote()) {
84: 
85:   auto cert_validator_name = getCertValidatorName(config.certificateValidationContext());
86:   auto cert_validator_factory =
87:       Registry::FactoryRegistry<CertValidatorFactory>::getFactory(cert_validator_name);
88: 
89:   if (!cert_validator_factory) {
90:     creation_status = absl::InvalidArgumentError(
91:         absl::StrCat("Failed to get certificate validator factory for ", cert_validator_name));
92:     return;
93:   }
94: 
95:   cert_validator_ = cert_validator_factory->createCertValidator(
96:       config.certificateValidationContext(), stats_, factory_context_);
97: 
98:   const auto tls_certificates = config.tlsCertificates();
99:   tls_contexts_.resize(std::max(static_cast<size_t>(1), tls_certificates.size()));
100: 
101:   std::vector<SSL_CTX*> ssl_contexts(tls_contexts_.size());
102:   for (size_t i = 0; i < tls_contexts_.size(); i++) {
103:     auto& ctx = tls_contexts_[i];
104:     ctx.ssl_ctx_.reset(SSL_CTX_new(TLS_method()));
105:     ssl_contexts[i] = ctx.ssl_ctx_.get();
106: 
107:     int rc = SSL_CTX_set_app_data(ctx.ssl_ctx_.get(), this);
108:     RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
109: 
110:     rc = SSL_CTX_set_min_proto_version(ctx.ssl_ctx_.get(), config.minProtocolVersion());
111:     RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
112: 
113:     rc = SSL_CTX_set_max_proto_version(ctx.ssl_ctx_.get(), config.maxProtocolVersion());
114:     RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
115: 
116:     if (!capabilities_.provides_ciphers_and_curves &&
117:         !SSL_CTX_set_strict_cipher_list(ctx.ssl_ctx_.get(), config.cipherSuites().c_str())) {
118:       // Break up a set of ciphers into each individual cipher and try them each individually in
119:       // order to attempt to log which specific one failed. Example of config.cipherSuites():
120:       // "-ALL:[ECDHE-ECDSA-AES128-GCM-SHA256|ECDHE-ECDSA-CHACHA20-POLY1305]:ECDHE-ECDSA-AES128-SHA".
121:       //
122:       // "-" is both an operator when in the leading position of a token (-ALL: don't allow this
123:       // cipher), and the common separator in names (ECDHE-ECDSA-AES128-GCM-SHA256). Don't split on
124:       // it because it will separate pieces of the same cipher. When it is a leading character, it
125:       // is removed below.
126:       std::vector<absl::string_view> ciphers =
127:           StringUtil::splitToken(config.cipherSuites(), ":+![|]", false);
128:       std::vector<std::string> bad_ciphers;
129:       for (const auto& cipher : ciphers) {
130:         std::string cipher_str(cipher);
131: 
132:         if (absl::StartsWith(cipher_str, "-")) {
133:           cipher_str.erase(cipher_str.begin());
134:         }
135: 
136:         if (!SSL_CTX_set_strict_cipher_list(ctx.ssl_ctx_.get(), cipher_str.c_str())) {
137:           bad_ciphers.push_back(cipher_str);
138:         }
139:       }
140:       creation_status = absl::InvalidArgumentError(
141:           fmt::format("Failed to initialize cipher suites {}. The following "
142:                       "ciphers were rejected when tried individually: {}",
143:                       config.cipherSuites(), absl::StrJoin(bad_ciphers, ", ")));
144:       return;
145:     }
146: 
147:     if (!capabilities_.provides_ciphers_and_curves &&
148:         !SSL_CTX_set1_curves_list(ctx.ssl_ctx_.get(), config.ecdhCurves().c_str())) {
149:       creation_status = absl::InvalidArgumentError(
150:           absl::StrCat("Failed to initialize ECDH curves ", config.ecdhCurves()));
151:       return;
152:     }
153: 
154:     // Set signature algorithms if given, otherwise fall back to BoringSSL defaults.
155:     if (!capabilities_.provides_sigalgs && !config.signatureAlgorithms().empty()) {
156:       if (!SSL_CTX_set1_sigalgs_list(ctx.ssl_ctx_.get(), config.signatureAlgorithms().c_str())) {
157:         creation_status = absl::InvalidArgumentError(absl::StrCat(
158:             "Failed to initialize TLS signature algorithms ", config.signatureAlgorithms()));
159:         return;
160:       }
161:     }
162:   }
163: 
164:   auto verify_mode_or_error = cert_validator_->initializeSslContexts(
165:       ssl_contexts, config.capabilities().provides_certificates);
166:   SET_AND_RETURN_IF_NOT_OK(verify_mode_or_error.status(), creation_status);
167:   auto verify_mode = verify_mode_or_error.value();
168: 
169:   if (!capabilities_.verifies_peer_certificates) {
170:     for (auto ctx : ssl_contexts) {
171:       if (verify_mode != SSL_VERIFY_NONE) {
172:         // TODO(danzh) Envoy's use of SSL_VERIFY_NONE does not quite match the actual semantics as
173:         // a client. As a client, SSL_VERIFY_NONE means to verify the certificate (which will fail
174:         // without trust anchors), save the result in the session ticket, but otherwise continue
175:         // with the handshake. But Envoy actually wants it to accept all certificates. The
176:         // disadvantage of using SSL_VERIFY_NONE is that it records the verify_result, which Envoy
177:         // never queries but gets saved in session tickets, and tries to find an anchor that isn't
178:         // there. And also it differs from server side behavior of SSL_VERIFY_NONE which won't
179:         // even request client certs. So, instead, we should configure a callback to skip
180:         // validation and always supply the callback to boring SSL.
181:         SSL_CTX_set_custom_verify(ctx, verify_mode, customVerifyCallback);
182:         SSL_CTX_set_reverify_on_resume(ctx, /*reverify_on_resume_enabled)=*/1);
183:       }
184:     }
185:   }
186: 
187: #ifdef BORINGSSL_FIPS
188:   if (!capabilities_.is_fips_compliant) {
189:     creation_status = absl::InvalidArgumentError(
190:         "Can't load a FIPS noncompliant custom handshaker while running in FIPS compliant mode.");
191:     return;
192:   }
193: #endif
194: 
195:   if (!capabilities_.provides_certificates) {
196:     for (uint32_t i = 0; i < tls_certificates.size(); ++i) {
197:       auto& ctx = tls_contexts_[i];
198:       // Load certificate chain.
199:       const auto& tls_certificate = tls_certificates[i].get();
200:       if (!tls_certificate.pkcs12().empty()) {
201:         creation_status = ctx.loadPkcs12(tls_certificate.pkcs12(), tls_certificate.pkcs12Path(),
202:                                          tls_certificate.password());
203:       } else {
204:         creation_status = ctx.loadCertificateChain(tls_certificate.certificateChain(),
205:                                                    tls_certificate.certificateChainPath());
206:       }
207:       if (!creation_status.ok()) {
208:         return;
209:       }
210:       // The must staple extension means the certificate promises to carry
211:       // with it an OCSP staple. https://tools.ietf.org/html/rfc7633#section-6
212:       constexpr absl::string_view tls_feature_ext = "1.3.6.1.5.5.7.1.24";
213:       constexpr absl::string_view must_staple_ext_value = "\x30\x3\x02\x01\x05";
214:       auto must_staple = Utility::getCertificateExtensionValue(*ctx.cert_chain_, tls_feature_ext);
215:       if (must_staple == must_staple_ext_value) {
216:         ctx.is_must_staple_ = true;
217:       }
218: 
219:       bssl::UniquePtr<EVP_PKEY> public_key(X509_get_pubkey(ctx.cert_chain_.get()));
220:       const int pkey_id = EVP_PKEY_id(public_key.get());
221:       ctx.is_ecdsa_ = pkey_id == EVP_PKEY_EC;
222:       switch (pkey_id) {
223:       case EVP_PKEY_EC: {
224:         // We only support P-256 ECDSA today.
225:         const EC_KEY* ecdsa_public_key = EVP_PKEY_get0_EC_KEY(public_key.get());
226:         // Since we checked the key type above, this should be valid.
227:         ASSERT(ecdsa_public_key != nullptr);
228:         const EC_GROUP* ecdsa_group = EC_KEY_get0_group(ecdsa_public_key);
229:         if (ecdsa_group == nullptr ||
230:             EC_GROUP_get_curve_name(ecdsa_group) != NID_X9_62_prime256v1) {
231:           creation_status = absl::InvalidArgumentError(
232:               fmt::format("Failed to load certificate chain from {}, only P-256 "
233:                           "ECDSA certificates are supported",
234:                           ctx.cert_chain_file_path_));
235:           return;
236:         }
237:         ctx.is_ecdsa_ = true;
238:       } break;
239:       case EVP_PKEY_RSA: {
240:         // We require RSA certificates with 2048-bit or larger keys.
241:         const RSA* rsa_public_key = EVP_PKEY_get0_RSA(public_key.get());
242:         // Since we checked the key type above, this should be valid.
243:         ASSERT(rsa_public_key != nullptr);
244:         const unsigned rsa_key_length = RSA_bits(rsa_public_key);
245: #ifdef BORINGSSL_FIPS
246:         if (rsa_key_length != 2048 && rsa_key_length != 3072 && rsa_key_length != 4096) {
247:           creation_status = absl::InvalidArgumentError(
248:               fmt::format("Failed to load certificate chain from {}, only RSA certificates with "
249:                           "2048-bit, 3072-bit or 4096-bit keys are supported in FIPS mode",
250:                           ctx.cert_chain_file_path_));
