474: enum ssl_verify_result_t ContextImpl::customVerifyCallback(SSL* ssl, uint8_t* out_alert) {
475:   auto* extended_socket_info = reinterpret_cast<Envoy::Ssl::SslExtendedSocketInfo*>(
476:       SSL_get_ex_data(ssl, ContextImpl::sslExtendedSocketInfoIndex()));
477:   if (extended_socket_info->certificateValidationResult() != Ssl::ValidateStatus::NotStarted) {
478:     if (extended_socket_info->certificateValidationResult() == Ssl::ValidateStatus::Pending) {
479:       return ssl_verify_retry;
480:     }
481:     ENVOY_LOG(trace, "Already has a result: {}",
482:               static_cast<int>(extended_socket_info->certificateValidationStatus()));
483:     // Already has a binary result, return immediately.
484:     *out_alert = extended_socket_info->certificateValidationAlert();
485:     return extended_socket_info->certificateValidationResult() == Ssl::ValidateStatus::Successful
486:                ? ssl_verify_ok
487:                : ssl_verify_invalid;
488:   }
489:   // Hasn't kicked off any validation for this connection yet.
490:   SSL_CTX* ssl_ctx = SSL_get_SSL_CTX(ssl);
491:   ContextImpl* context_impl = static_cast<ContextImpl*>(SSL_CTX_get_app_data(ssl_ctx));
492:   auto transport_socket_options_shared_ptr_ptr =
493:       static_cast<const Network::TransportSocketOptionsConstSharedPtr*>(SSL_get_app_data(ssl));
494:   ASSERT(transport_socket_options_shared_ptr_ptr);
495:   ValidationResults result = context_impl->customVerifyCertChain(
496:       extended_socket_info, *transport_socket_options_shared_ptr_ptr, ssl);
497:   switch (result.status) {
498:   case ValidationResults::ValidationStatus::Successful:
499:     return ssl_verify_ok;
500:   case ValidationResults::ValidationStatus::Pending:
501:     return ssl_verify_retry;
502:   case ValidationResults::ValidationStatus::Failed: {
503:     if (result.tls_alert.has_value() && out_alert) {
504:       *out_alert = result.tls_alert.value();
505:     }
506:     return ssl_verify_invalid;
507:   }
508:   }
509:   PANIC("not reached");
510: }
