68:   const uint8_t* alpn_data = parsed_alpn_protocols_.data();
69:   size_t alpn_data_size = parsed_alpn_protocols_.size();
70: 
71:   if (SSL_select_next_proto(const_cast<unsigned char**>(out), outlen, alpn_data, alpn_data_size, in,
72:                             inlen) != OPENSSL_NPN_NEGOTIATED) {
73:     return SSL_TLSEXT_ERR_NOACK;
74:   } else {
75:     return SSL_TLSEXT_ERR_OK;
76:   }
77: }
